function scenarioOutputs(s,years){const defs=[["Baseline",0,0,0,0],["Conservative",.75,.75,1.15,.8],["Expected",1,1,1,1],["Ambitious",1.15,1.25,1.05,1.1],["Stress test",.6,.65,1.3,.65]];return defs.map(d=>{const cap=n(s.capex,950000)*d[3];const sav=n(s.annualSavings,185000)*d[4];return{label:d[0],annualAvoided:n(s.baselineEmissions,1200)*(n(s.reductionRate,32)*d[1]/100)*Math.min(100,n(s.adoptionRate,65)*d[2])/100,npv:npv(cap,sav,n(s.discountRate,7),years),payback:sav>0?cap/sav:Infinity}})}
function calculate(s){const years=Math.max(1,Math.round(n(s.modelYears,5)));const p=complexityPenalty(s.complexity);const baseline=n(s.baselineEmissions,1200),reduction=n(s.reductionRate,32),adoption=n(s.adoptionRate,65),capex=n(s.capex,950000),savings=n(s.annualSavings,185000);const npvValue=npv(capex,savings,n(s.discountRate,7),years);const annualAvoided=baseline*(reduction/100)*(adoption/100);const totalAvoided=annualAvoided*years;const payback=savings>0?capex/savings:Infinity;const roi=capex>0?((savings*years-capex)/capex)*100:0;const env=clamp(30+reduction*.45+adoption*.22-p*.35,0,100);const social=clamp(56+n(s.socialBenefit,58)*.18+adoption*.08-p*.42,0,100);const econ=clamp(48+(npvValue/Math.max(capex,1))*34+Math.min(20,roi/6)-p*.48,0,100);const gov=clamp(45+n(s.governanceReadiness,68)*.45+n(s.dataConfidence,70)*.12-p*.3,0,100);const wsum=Math.max(1,n(s.weightEnv,30)+n(s.weightSocial,20)+n(s.weightEconomic,30)+n(s.weightGovernance,20));const weighted=(env*n(s.weightEnv,30)+social*n(s.weightSocial,20)+econ*n(s.weightEconomic,30)+gov*n(s.weightGovernance,20))/wsum;const risk=clamp((n(s.exposure,55)*.35+n(s.vulnerability,48)*.35+n(s.stakeholderSensitivity,45)*.2-n(s.resilience,62)*.18-n(s.governanceReadiness,68)*.08+20),0,100);return{scores:{environmental:env,social:social,economic:econ,governance:gov,weighted:weighted},finance:{npv:npvValue,payback_years:payback,roi_percent:roi},emissions:{annual_avoided_tco2e:annualAvoided,total_avoided_tco2e:totalAvoided},risk:{risk_score:risk,risk_level:risk>=70?"High":risk>=45?"Medium":"Low"},scenarios:scenarioOutputs(s,years),status:weighted>=75&&risk<55?"Strong candidate with review":weighted>=60?"Promising but needs mitigation":"Needs redesign or stronger evidence",years:years,workbench_shortcodes:["[sc_workbench mode=\"tool\" display=\"compact\" tool=\"risk-resilience-impact-matrix\"]","[sc_workbench mode=\"tool\" display=\"compact\" tool=\"economics-forecasting-and-scenario-tool\"]","[sc_workbench mode=\"tool\" display=\"drawer\" tool=\"environmental-monitoring-qaqc-tool\"]"]}}
function bar(v){return '<div class="scds-bar"><i style="width:'+clamp(v,0,100)+'%"></i></div>'}
function card(label,value){return '<div class="scds-result-card"><strong>'+esc(label)+'</strong><span>'+value+'</span></div>'}
function scoreTable(r){const rows=[["Environmental",r.scores.environmental],["Social",r.scores.social],["Economic",r.scores.economic],["Governance",r.scores.governance]];return '<table class="scds-table"><thead><tr><th>Pillar</th><th>Score</th><th>Diagnostic</th></tr></thead><tbody>'+rows.map(x=>'<tr><td>'+x[0]+'</td><td>'+pct.format(x[1])+'</td><td>'+bar(x[1])+'</td></tr>').join('')+'</tbody></table>'}
