function compactText(v,d){if(v===undefined||v===null||v==="")return d||"Not specified";if(Array.isArray(v))return v.map(x=>compactText(x,"")).filter(Boolean).join("; ")||d||"Not specified";if(typeof v==="object"){for(const k of ["name","title","label","summary","description","value"])if(v[k])return String(v[k]);return JSON.stringify(v).slice(0,220)}return String(v)}
function moneyText(v){const x=Number(v);return Number.isFinite(x)?money.format(x):compactText(v,"n/a")}
function briefNum(v,suf){const x=Number(v);return Number.isFinite(x)?pct.format(x)+(suf||""):compactText(v,"n/a")}
