function integratedBriefMarkdown(brief){function bullets(items){return Array.isArray(items)&&items.length?items.map(x=>"- "+compactText(x,"")).join("\n"):"- None recorded."}const parts=["# "+compactText(brief.title,"Integrated Decision Brief"),"","**Decision Packet:** "+compactText(brief.decision_packet_id,"SCDS-DRAFT"),"**Recommendation posture:** "+compactText(brief.recommendation_posture,"Review required"),"**Brief readiness:** "+compactText((brief.brief_readiness||{}).readiness_percent,"n/a")+"%","","## Executive Summary",compactText(brief.executive_summary,""),"","## Decision Question",compactText(brief.decision_question,"Not specified")];[["Problem Framing",[compactText((brief.problem_framing||{}).summary,"Not specified")]], ["Four-Pillar Sustainability Analysis",(brief.four_pillar_analysis||{}).findings], ["Scenario Comparison",(brief.scenario_comparison||{}).findings], ["Financial Tradeoffs",(brief.financial_tradeoffs||{}).findings], ["Impact Measurement",(brief.impact_measurement||{}).findings], ["Claim and Narrative Risk",(brief.claim_and_narrative_risk||{}).findings], ["Execution and Recovery Risk",(brief.execution_and_recovery||{}).findings], ["Assumptions and Uncertainties",(brief.assumptions_and_uncertainties||{}).findings], ["Evidence and Source Ledger",(brief.evidence_and_source_ledger||{}).findings], ["Audit Appendix Summary",(brief.audit_appendix_summary||{}).findings], ["Next Review Actions",brief.next_review_actions]].forEach(x=>{parts.push("","## "+x[0],bullets(x[1]))});parts.push("","## Boundaries","Educational decision support only. Not professional advice, certification, assurance, or approval.");return parts.join("\n")+"\n"}

function localBriefReadiness(root,s,r){const packet=root._scdsPacket||{};const audit=root._scdsAudit||{};const sources=(Array.isArray(packet.sources)?packet.sources.length:0)+(Array.isArray(audit.source_ledger)?audit.source_ledger.length:0);const assumptions=Array.isArray(packet.assumptions)?packet.assumptions.length:0;const calculations=Array.isArray(packet.calculation_trace)?packet.calculation_trace.length:0;const has=(v)=>!(v===undefined||v===null||v===''||(Array.isArray(v)&&!v.length)||(typeof v==='object'&&!Array.isArray(v)&&!Object.keys(v).length));const sections=[['framing','Problem Framing',has(packet.decision_framing||packet.framing)||!!s.decisionQuestion,true,false],['evidence','Evidence & Measurement',sources>0,true,false],['scenarios','Scenario Analysis',has((packet.scenarios||{}).records||packet.scenario_analysis)||!!(r.scenarios&&r.scenarios.length),false,false],['impact','Impact Measurement',has((packet.impact_measurement||{}).records||packet.impact_records),true,false],['claims','Claim & Narrative Risk',has((packet.claim_and_risk_review||{}).records||packet.claim_reviews||(audit.claim_trace||[])),true,true],['finance','Financial Tradeoffs',has(packet.financial_tradeoffs||packet.finance_analysis||r.finance),true,true],['recovery','Execution & Recovery',has(packet.execution_and_recovery||packet.execution_recovery),false,false],['audit','Audit & Provenance',has(audit)||has(packet.audit_and_provenance),true,false],['synthesis','Integrated Brief',has(r.scores),true,false]];let issues=[];const rows=sections.map(x=>{let score=x[2]?70:0;if(x[0]==='evidence'&&!sources){issues.push({severity:'critical',section:x[0],issue:'No source or evidence records are attached.',action:'Import Catalyst Data records or generate the audit after adding sources.'});}if(x[0]==='impact'&&!x[2])issues.push({severity:'high',section:x[0],issue:'Impact record is missing.',action:'Import Global Impact Catalyst.'});if(x[0]==='claims'&&!x[2])issues.push({severity:'high',section:x[0],issue:'Claim review is missing.',action:'Import Narrative Risk before publishing external claims.'});if(x[0]==='finance'){if(s.capex>0&&s.annualSavings>0)score+=15; if(!assumptions)issues.push({severity:'medium',section:x[0],issue:'No imported assumptions register is attached.',action:'Generate audit/provenance before final export.'});}if(x[0]==='audit'){if(sources)score+=15;if(assumptions)score+=10;if(calculations)score+=10;if(!sources)issues.push({severity:'critical',section:x[0],issue:'Audit source ledger is incomplete.',action:'Add source records before reviewed export.'});}score=Math.max(0,Math.min(100,score));let high=issues.some(i=>i.section===x[0]&&i.severity==='high'),crit=issues.some(i=>i.section===x[0]&&i.severity==='critical');let state=score<=0?'not_started':(crit?'needs_evidence':(x[4]&&(high||score<90)?'needs_expert_review':(score<70||high?'needs_review':(score<90?'ready_for_draft':'ready_for_export'))));return{id:x[0],label:x[1],score:score,required:x[3],expert_review:x[4],present:x[2],review_state:state,status_label:state.replaceAll('_',' ').replace(/\b\w/g,c=>c.toUpperCase()),flags:issues.filter(i=>i.section===x[0])}});const weights={framing:10,evidence:16,scenarios:10,impact:12,claims:12,finance:14,recovery:8,audit:10,synthesis:8};let total=0,weighted=0;rows.forEach(row=>{total+=weights[row.id]||10;weighted+=(weights[row.id]||10)*row.score});const readiness=Math.round((weighted/Math.max(1,total))*10)/10;const critical=issues.filter(i=>i.severity==='critical').length,high=issues.filter(i=>i.severity==='high').length;const expert=rows.filter(r=>r.review_state==='needs_expert_review').length;const requiredBlock=rows.some(r=>r.required&&['not_started','needs_evidence'].includes(r.review_state));const overall=(critical||requiredBlock)?'needs_evidence':(expert?'needs_expert_review':(readiness>=85&&!high?'ready_for_export':(readiness>=65?'ready_for_draft':'needs_review')));return{ok:true,version:'2.0.1',readiness:{ok:true,version:'2.0.1',readiness_version:'2.0.1',readiness_percent:readiness,overall_review_state:overall,overall_status_label:overall.replaceAll('_',' ').replace(/\b\w/g,c=>c.toUpperCase()),sections:rows,unresolved_issues:issues,counts:{sources:sources,assumptions:assumptions,calculations:calculations,critical_issues:critical,high_issues:high,sections_ready_for_export:rows.filter(r=>r.review_state==='ready_for_export').length,sections_needing_expert_review:expert},export_gate:{draft_brief_allowed:readiness>=50,reviewed_export_allowed:readiness>=75&&!critical&&!requiredBlock,professional_reliance_allowed:false,blocking_issues:issues.filter(i=>['critical','high'].includes(i.severity))},required_reviews:['Data/source review','Finance assumptions review','Narrative/claim risk review','Professional review where regulated or safety-critical use is possible'],next_actions:[...new Set(issues.slice(0,8).map(i=>i.action||i.issue))],warnings:['Brief readiness is a workflow quality gate, not approval, assurance, certification, or professional signoff.']},decision_packet:packet,results:r,audit:audit}}
function readinessHtml(data){const rd=(data&&data.readiness)||data||{};const gate=rd.export_gate||{};let html='<div class="scds-readiness-card"><p class="scds-card-label">Brief readiness v'+esc(rd.readiness_version||'2.0.1')+'</p><h4>'+esc(rd.overall_status_label||'Needs Review')+' · '+esc(rd.readiness_percent||0)+'%</h4><div class="scds-readiness-meter"><span style="width:'+Math.max(0,Math.min(100,Number(rd.readiness_percent||0)))+'%"></span></div><p><strong>Draft brief:</strong> '+(gate.draft_brief_allowed?'Allowed':'Not ready')+' · <strong>Reviewed export:</strong> '+(gate.reviewed_export_allowed?'Allowed':'Blocked')+' · <strong>Professional reliance:</strong> Not allowed without qualified review.</p>';html+='<div class="scds-readiness-grid">';(rd.sections||[]).forEach(s=>{html+='<article><p class="scds-card-label">'+esc(s.label)+'</p><h5>'+esc(s.status_label)+' · '+esc(s.score)+'%</h5><p>'+esc(s.required?'Required section':'Supporting section')+(s.expert_review?' · expert review gate':'')+'</p></article>'});html+='</div>';if((rd.unresolved_issues||[]).length){html+='<h4>Unresolved issues</h4><ul>';rd.unresolved_issues.forEach(i=>{html+='<li><strong>'+esc(i.severity||'review')+':</strong> '+esc(i.issue||'Review issue')+' <em>'+esc(i.action||'')+'</em></li>'});html+='</ul>'}if((rd.next_actions||[]).length){html+='<h4>Next review actions</h4>'+listHtml(rd.next_actions)}return html+'</div>'}
function generateReadiness(root){const cfg=window.SCDSDecisionStudio||{};const s=collect(root);const r=(root._scdsLast&&root._scdsLast.results)||calculate(s);const target=$(root,'[data-scds-readiness-output]')||$(root,'[data-scds-output]');if(target)target.innerHTML='<p>Checking brief readiness…</p>';request(cfg.restBriefReadinessUrl,{inputs:s,results:r,packet:root._scdsPacket||{},audit:root._scdsAudit||{}}).then(data=>{root._scdsReadiness=data;if(target)target.innerHTML=readinessHtml(data);}).catch(err=>{const data=localBriefReadiness(root,s,r);root._scdsReadiness=data;if(target)target.innerHTML=readinessHtml(data)+'<p class="scds-note">Backend readiness route unavailable; showing browser-generated fallback.</p>';});}
