function scenarioValue(x,a,b,c){return x[a]??x[b]??x[c]}
function localScenarioComparison(root,s,r){const scenarios=((root._scdsPacket&&root._scdsPacket.scenarios&&root._scdsPacket.scenarios.records)||r.scenarios||[]);const baseline=scenarios[0]||{};const rows=scenarios.map((x,i)=>{const annual=n(scenarioValue(x,'annual_avoided_tco2e','annualAvoided','annual_avoided'),0);const npvValue=Number.isFinite(Number(x.npv))?Number(x.npv):null;const payback=Number.isFinite(Number(x.payback_years??x.payback))?Number(x.payback_years??x.payback):null;const risk=n(x.risk_score??r.risk.risk_score,50);const conf=n(x.confidence??s.dataConfidence,70);const emissionsComponent=clamp((annual/Math.max(1,n(s.baselineEmissions,1200)))*100,0,100);const npvComponent=npvValue===null?50:clamp(50+(npvValue/Math.max(1,n(s.capex,950000)))*35,0,100);const paybackComponent=payback===null?50:clamp(100-(payback/Math.max(1,n(s.modelYears,5)))*55,0,100);const score=clamp(emissionsComponent*.26+npvComponent*.26+paybackComponent*.16+(100-risk)*.20+conf*.12,0,100);return{option_id:'scenario-'+(i+1),label:x.label||x.name||x.scenario||('Option '+(i+1)),annual_avoided_tco2e:annual,total_avoided_tco2e:n(x.total_avoided_tco2e,annual*Math.max(1,n(s.modelYears,5))),npv:npvValue,payback_years:payback,risk_score:risk,confidence:conf,decision_score:Math.round(score*100)/100,implementation_complexity:x.implementation_complexity||x.complexity||s.complexity||'Medium',interpretation:x.interpretation||x.decision_note||x.summary||'Scenario generated from Decision Studio assumptions or imported artifact.'}});const base=rows[0]||{};rows.forEach(row=>{row.delta_vs_baseline={annual_avoided_tco2e:(row.annual_avoided_tco2e||0)-(base.annual_avoided_tco2e||0),npv:(row.npv==null||base.npv==null)?null:row.npv-base.npv,risk_score:(row.risk_score||0)-(base.risk_score||0)};row.tradeoff_note=row.decision_score>=70?'High-scoring option; verify assumptions and implementation limits before export.':row.decision_score>=50?'Moderate option; review tradeoffs, sources, and mitigation requirements.':'Weak option under current assumptions; consider redesign or stronger evidence.'});const ranked=[...rows].sort((a,b)=>(b.decision_score||0)-(a.decision_score||0));return{ok:true,version:'2.0.1',scenario_comparison:{comparison_version:'2.0.1',scenario_count:rows.length,recommended_option:(ranked[0]&&ranked[0].label)||'No option selected',recommended_option_id:(ranked[0]&&ranked[0].option_id)||null,matrix:rows,ranked_options:ranked,sensitivity_flags:['Review savings volatility and CAPEX volatility before treating scenario ranks as stable.','Use Workbench Graph Studio or economics forecasting for deeper sensitivity curves.','Use Catalyst Data records to replace screening-level assumptions with source-backed indicators.'],workbench_handoff_candidates:['economics-forecasting-and-scenario-tool','risk-resilience-impact-matrix','graph-studio-parameter-sensitivity','environmental-monitoring-qaqc-tool'],warnings:['Scenario comparison is a decision-support screen, not a forecast.']},results:r,decision_packet:root._scdsPacket||{}}}
