function scenarioJsonObject(root,selector,fallback){const el=$(root,selector);if(!el||!String(el.value||'').trim())return fallback||{};try{const data=JSON.parse(el.value);return data&&typeof data==='object'&&!Array.isArray(data)?data:(fallback||{})}catch(e){throw new Error(selector+' contains invalid JSON: '+e.message)}}
