const tornado=((studio.one_way_sensitivity||{}).tornado_ranking)||[];if(tornado.length){html+='<h4>Sensitivity ranking</h4><div class="scds-table-wrap"><table class="scds-table"><thead><tr><th>Parameter</th><th>Decision-score range</th></tr></thead><tbody>'+tornado.map(x=>'<tr><td>'+esc(x.parameter)+'</td><td>'+esc(x.score_range)+'</td></tr>').join('')+'</tbody></table></div>'}
const threshold=studio.threshold_analysis||{};if(threshold.parameter){html+='<h4>Threshold / break-even</h4><div class="scds-readiness-card"><p><strong>'+esc(threshold.metric)+' '+esc(threshold.operator)+' '+esc(threshold.target_value)+'</strong> by varying '+esc(threshold.parameter)+'.</p><p>'+(threshold.found&&threshold.break_even?'First screening crossing: <strong>'+esc(threshold.break_even.parameter_value)+'</strong> (metric '+esc(threshold.break_even.metric_value)+').':'No crossing was found inside the supplied range.')+'</p></div>'}
